          return new ApiInfoBuilder()
                  .title("Spring Boot中使用Swagger2构建RESTful APIs")
                  .description("更多Spring Boot相关文章请关注：https://img.jacian.com/<br><br><h3>Create By Ricky Liu</h3>")
                  //.termsOfServiceUrl("https://img.jacian.com/")
                  //.contact("Ricky Liu")
                  .version("1.0")
                  .build();
      }
  }
